# Verify
ids = list(new_desc.keys()) + [317]
for book in data:
    if book['id'] in ids:
        d = len(book['description'])
        status = 'OK' if 125 <= d <= 150 else f'BAD({d})'
        print(f'ID={book["id"]:3d} {status}: {book["description"][:60]}')
